#include<bits/stdc++.h>
#define ll long long
using namespace std;
int n[4],a[4][25],ans=0,Z,Y,mi;
void dfs(int x,int y){
	if(x>=n[y]){mi=min(mi,max(Z,Y));return;}
	Z+=a[y][x];dfs(x+1,y);
	Z-=a[y][x],Y+=a[y][x];
	dfs(x+1,y);Y-=a[y][x];
}int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	for(int i=0;i<4;++i)scanf("%d",n+i);
    for(int i=0;i<4;++i){
    	for(int j=0;j<n[i];++j)scanf("%d",&(a[i][j]));
    	Z=Y=0,mi=INT_MAX;
    	dfs(0,i);ans+=mi;
	}printf("%d",ans);
    return false;
}
